import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withFirstRecordAsHeader();
        assertNotNull(result, "Resulting CSVFormat should not be null");
        assertNotSame(format, result, "withFirstRecordAsHeader() should return a new CSVFormat instance");
        // The result should have header set (not null)
        assertNotNull(result.getHeader(), "Header should be set");
        // The result should skip header record
        assertTrue(result.getSkipHeaderRecord(), "SkipHeaderRecord should be true");
    }
}
